import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const m=JSON.parse('{"title":"世界构建","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/世界构建.md","filePath":"mumuainovel/世界构建.md","lastUpdated":1777605420000}'),e={name:"mumuainovel/世界构建.md"};function i(c,s,t,o,u,r){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="世界构建" tabindex="-1">世界构建 <a class="header-anchor" href="#世界构建" aria-label="Permalink to &quot;世界构建&quot;">​</a></h1><blockquote><p>模板键: <code>WORLD_BUILDING</code> 分类: 世界构建 描述: 用于生成小说世界观设定，包括时间背景、地理位置、氛围基调和世界规则 参数: [&quot;title&quot;, &quot;theme&quot;, &quot;genre&quot;, &quot;description&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是资深的世界观设计师，擅长为{genre}类型的小说构建真实、自洽的世界观。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【设计任务】</span></span>
<span class="line"><span>为小说《{title}》构建完整的世界观设定。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【核心要求】</span></span>
<span class="line"><span>- 主题契合：世界观必须支撑主题&quot;{theme}&quot;</span></span>
<span class="line"><span>- 简介匹配：为简介中的情节提供合理背景</span></span>
<span class="line"><span>- 类型适配：符合{genre}类型的特征</span></span>
<span class="line"><span>- 规模适当：根据题材选择合适的设定尺度</span></span>
<span class="line"><span>- 冲突土壤：世界观必须内含矛盾和冲突，为故事发展提供张力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;input priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span>简介：{description}</span></span>
<span class="line"><span>&lt;/input&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;guidelines priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【类型指导原则】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**现代都市/言情/青春**：</span></span>
<span class="line"><span>- 时间：当代社会（2020年代）或近未来（2030-2050年）</span></span>
<span class="line"><span>- 避免：大崩解、纪元、末日等宏大概念</span></span>
<span class="line"><span>- 重点：具体城市环境、职场文化、社会现状</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**历史/古代**：</span></span>
<span class="line"><span>- 时间：明确的历史朝代或虚构古代</span></span>
<span class="line"><span>- 重点：时代特征、礼教制度、阶级分化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**玄幻/仙侠/修真**：</span></span>
<span class="line"><span>- 时间：修炼文明的特定时期</span></span>
<span class="line"><span>- 重点：修炼规则、灵气环境、门派势力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**科幻**：</span></span>
<span class="line"><span>- 时间：未来明确时期（如2150年、星际时代初期）</span></span>
<span class="line"><span>- 重点：科技水平、社会形态、文明转折</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**奇幻/魔法**：</span></span>
<span class="line"><span>- 时间：魔法文明的特定阶段</span></span>
<span class="line"><span>- 重点：魔法体系、种族关系、大陆格局</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**设定尺度控制**：</span></span>
<span class="line"><span>- 现代都市：聚焦某个城市、行业、阶层</span></span>
<span class="line"><span>- 校园青春：学校环境、学生生活、成长困境</span></span>
<span class="line"><span>- 职场言情：公司文化、行业特点、职业压力</span></span>
<span class="line"><span>- 史诗题材：才需要宏大的世界观架构</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【各类型常见陷阱 - 避免】</span></span>
<span class="line"><span>**现代都市**：不要无中生有添加超自然元素、不要把普通职场写成宫斗</span></span>
<span class="line"><span>**玄幻仙侠**：不要堆砌修炼等级名词而无实际描述、不要用&quot;天才废柴&quot;等陈旧套路</span></span>
<span class="line"><span>**科幻**：不要堆砌术语而忽略人文社会层面、不要脱离简介设定</span></span>
<span class="line"><span>**历史古代**：不要用现代价值观评判、不要出现时代错位的物品或用语</span></span>
<span class="line"><span>**奇幻魔法**：不要照搬西方中世纪模板、不要忽略经济和民生细节</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/guidelines&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>生成包含以下四个字段的JSON对象，每个字段300-500字：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. **time_period**（时间背景与社会状态）</span></span>
<span class="line"><span>   - 根据类型设定合适规模的时间背景</span></span>
<span class="line"><span>   - 现代题材：具体社会特征（如：2024年北京，互联网行业高速发展）</span></span>
<span class="line"><span>   - 历史题材：明确朝代和阶段（如：明朝嘉靖年间，海禁政策下的沿海）</span></span>
<span class="line"><span>   - 幻想题材：文明发展阶段，具体而非空泛</span></span>
<span class="line"><span>   - 阐明时代核心矛盾和社会焦虑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. **location**（空间环境与地理特征）</span></span>
<span class="line"><span>   - 故事主要发生的空间环境</span></span>
<span class="line"><span>   - 现代题材：具体城市名或类型</span></span>
<span class="line"><span>   - 环境如何影响居民生存方式</span></span>
<span class="line"><span>   - 标志性场景描述</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. **atmosphere**（感官体验与情感基调）</span></span>
<span class="line"><span>   - 身临其境的感官细节（视觉、听觉、嗅觉）</span></span>
<span class="line"><span>   - 美学风格和色彩基调</span></span>
<span class="line"><span>   - 居民心理状态和情绪氛围</span></span>
<span class="line"><span>   - 与主题情感呼应</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. **rules**（世界规则与社会结构）</span></span>
<span class="line"><span>   - 世界运行的核心法则</span></span>
<span class="line"><span>   - 现代题材：社会规则、行业潜规则、人际法则</span></span>
<span class="line"><span>   - 幻想题材:力量体系、社会等级、资源分配</span></span>
<span class="line"><span>   - 权力结构和利益格局</span></span>
<span class="line"><span>   - 社会禁忌及后果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【各类型重点字段】</span></span>
<span class="line"><span>- 现代都市：location &gt; atmosphere &gt; rules &gt; time_period</span></span>
<span class="line"><span>- 玄幻仙侠：rules &gt; location &gt; time_period &gt; atmosphere</span></span>
<span class="line"><span>- 科幻：rules &gt; time_period &gt; location &gt; atmosphere</span></span>
<span class="line"><span>- 历史古代：time_period &gt; rules &gt; location &gt; atmosphere</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式规范】</span></span>
<span class="line"><span>- 纯JSON输出，以{{开始、}}结束</span></span>
<span class="line"><span>- 无markdown标记、代码块符号</span></span>
<span class="line"><span>- 字段值为完整段落文本</span></span>
<span class="line"><span>- 不使用特殊符号包裹内容</span></span>
<span class="line"><span>- 提供充实原创内容</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【JSON示例】</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;time_period&quot;: &quot;时间背景与社会状态的详细描述（300-500字）&quot;,</span></span>
<span class="line"><span>  &quot;location&quot;: &quot;空间环境与地理特征的详细描述（300-500字）&quot;,</span></span>
<span class="line"><span>  &quot;atmosphere&quot;: &quot;感官体验与情感基调的详细描述（300-500字）&quot;,</span></span>
<span class="line"><span>  &quot;rules&quot;: &quot;世界规则与社会结构的详细描述（300-500字）&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 简介契合：为简介情节提供合理背景</span></span>
<span class="line"><span>✅ 类型适配：符合{genre}的特征</span></span>
<span class="line"><span>✅ 主题贴合：支撑主题&quot;{theme}&quot;</span></span>
<span class="line"><span>✅ 具象化：用具体细节而非空洞概念</span></span>
<span class="line"><span>✅ 逻辑自洽：所有设定相互支撑</span></span>
<span class="line"><span>【字段间一致性】</span></span>
<span class="line"><span>✅ time_period中的时代特征，必须在location的空间描述中有对应体现</span></span>
<span class="line"><span>✅ atmosphere的感官基调必须与rules中的社会结构一致</span></span>
<span class="line"><span>✅ 四个字段形成完整统一的世界观，不能互相矛盾</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【冲突内蕴】</span></span>
<span class="line"><span>✅ 世界观中必须包含至少一个核心矛盾（阶级、资源、信仰、权力等）</span></span>
<span class="line"><span>✅ 社会规则（rules）中应存在可以被角色利用或挑战的张力</span></span>
<span class="line"><span>✅ 时间背景（time_period）应暗示时代变革或危机</span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 生成与类型不匹配的设定</span></span>
<span class="line"><span>❌ 为小规模题材使用宏大世界观</span></span>
<span class="line"><span>❌ 使用模板化、空泛的表达</span></span>
<span class="line"><span>❌ 输出markdown或代码块标记</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const q=n(e,[["render",i]]);export{m as __pageData,q as default};
